// A: Seq Scan — NO index used
//    Problem: full table scan of 50M rows to find 1
//    Rows Removed = 49999108 (almost entire table scanned and discarded)
//    Fix: CREATE INDEX idx_payments_merchant ON payments(merchant_id);

// B: Index Scan — YES, index being used
//    Good: using idx_payments_merchant, fast (0.8ms)
//    Still needs heap access (fetches actual row from table)
//    Could be improved with covering index if selecting many columns

// C: Index Only Scan — YES, BEST index type
//    All data served from index itself (Heap Fetches: 0)
//    No table access needed → covering index with INCLUDE
//    0.2ms — fastest possible

// D: Seq Scan — NO index used
//    Problem: LOWER(email) disables regular email index!
//    A regular CREATE INDEX ON payments(email) won't work for LOWER(email)
//    Fix: CREATE INDEX idx_payments_lower_email ON payments(LOWER(email));
//    Or: CREATE INDEX ON payments(email) and use WHERE email = lower_value

public class ExplainInterpretation {
    public static void main(String[] args) {
        System.out.println("A: Seq Scan → MISSING INDEX on merchant_id");
        System.out.println("B: Index Scan → good, but heap access needed");
        System.out.println("C: Index Only Scan → optimal, covering index");
        System.out.println("D: Seq Scan → index on LOWER(email) needed");
    }
}

// Index: idx_trades(user_id, symbol, executed_at)
// Leftmost prefix rule: must start from user_id to use this index

// A: WHERE user_id = 'U001'
//    YES: uses index. user_id is the leftmost column. Finds U001's trades.

// B: WHERE user_id = 'U001' AND symbol = 'TCS'
//    YES: uses index on (user_id, symbol). Two-column prefix. Finds U001's TCS trades.

// C: WHERE symbol = 'TCS'
//    NO: does NOT use index. symbol is not the leftmost column.
//    PostgreSQL would need a separate index on (symbol) or (symbol, ...)

// D: WHERE executed_at > '2024-01-01'
//    NO: does NOT use index. executed_at is third column, no leftmost prefix.

// E: WHERE symbol = 'TCS' AND executed_at > '2024-01-01'
//    NO: neither is the leftmost column. Full table scan.

// F: WHERE user_id = 'U001' AND executed_at > '2024-01-01'
//    PARTIAL: uses index for user_id (leftmost match), then filters executed_at.
//    NOT as efficient as F with all three columns. PostgreSQL may use index
//    on user_id alone, then filter executed_at from heap.

// G: WHERE user_id = 'U001' AND symbol = 'TCS' AND executed_at > '2024-01-01'
//    YES: full index used for all three columns. Most efficient.

public class LeftmostPrefixAnalysis {
    public static void main(String[] args) {
        System.out.println("A: YES - user_id is leftmost");
        System.out.println("B: YES - (user_id, symbol) prefix");
        System.out.println("C: NO  - symbol is not leftmost");
        System.out.println("D: NO  - executed_at is not leftmost");
        System.out.println("E: NO  - neither is leftmost");
        System.out.println("F: PARTIAL - user_id only");
        System.out.println("G: YES - all three columns used");
    }
}

// 4 SYMPTOMS OF POOL EXHAUSTION:
// 1. Log: 'HikariPool-1 - Connection is not available, request timed out after Nms'
// 2. Actuator: hikaricp.connections.pending > 0 (requests waiting for connection)
// 3. Application: 503/504 HTTP responses under load (requests timing out)
// 4. Actuator: hikaricp.connections.active == hikaricp.connections.total (100% pool used)

import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;
import io.micrometer.core.instrument.MeterRegistry;

@Service
public class PoolHealthMonitor {
    private final MeterRegistry registry;
    PoolHealthMonitor(MeterRegistry r) { registry = r; }

    @Scheduled(fixedRate = 60000)  // every minute
    public void logPoolHealth() {
        double active  = getValue("hikaricp.connections.active");
        double idle    = getValue("hikaricp.connections.idle");
        double pending = getValue("hikaricp.connections.pending");
        double total   = getValue("hikaricp.connections");

        System.out.printf("[Pool] total=%.0f active=%.0f idle=%.0f pending=%.0f%n",
            total, active, idle, pending);

        if (pending > 0) {
            System.err.printf("[Pool ALERT] %d requests waiting for connection!%n", (int)pending);
        }
        if (active / total > 0.8) {
            System.err.println("[Pool WARN] Pool >80% utilized — consider increasing size");
        }
    }
    private double getValue(String name) {
        var gauge = registry.find(name).gauge();
        return gauge != null ? gauge.value() : 0;
    }
}

