import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.*;
import javax.sql.DataSource;

@Configuration
public class DataSourceConfig {

    // Primary (write) — @Primary used by default JPA/repositories:
    @Bean @Primary
    public DataSource primaryDataSource(
            @Value("${spring.datasource.url}") String url,
            @Value("${spring.datasource.username}") String user,
            @Value("${spring.datasource.password}") String pass) {
        HikariConfig cfg = new HikariConfig();
        cfg.setJdbcUrl(url); cfg.setUsername(user); cfg.setPassword(pass);
        cfg.setMaximumPoolSize(15);
        cfg.setPoolName("Primary-Write-Pool");
        cfg.setConnectionTimeout(2000);
        return new HikariDataSource(cfg);
    }

    // Read replica — inject explicitly where needed:
    @Bean("replicaDataSource")
    public DataSource replicaDataSource(
            @Value("${app.datasource.replica.url}") String url,
            @Value("${app.datasource.replica.username}") String user,
            @Value("${app.datasource.replica.password}") String pass) {
        HikariConfig cfg = new HikariConfig();
        cfg.setJdbcUrl(url); cfg.setUsername(user); cfg.setPassword(pass);
        cfg.setMaximumPoolSize(30);  // larger: handles more read traffic
        cfg.setReadOnly(true);       // prevents accidental writes
        cfg.setPoolName("Replica-Read-Pool");
        return new HikariDataSource(cfg);
    }
}
// Route to REPLICA: read-heavy queries (order history, search, reports)
// Route to PRIMARY: any write (INSERT, UPDATE, DELETE) + reads that must be current
// Rule: use replica for analytics, dashboards, search; primary for user-facing mutations

