import com.zaxxer.hikari.*;
import org.springframework.boot.context.properties.*;
import org.springframework.context.annotation.*;
import org.springframework.boot.autoconfigure.jdbc.DataSourceProperties;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.binder.db.HikariDataSourceMetrics;
import javax.sql.DataSource;

// Pool settings POJO:
@ConfigurationProperties(prefix = "app.datasource")
public class AppDataSourceProperties {
    private String url;
    private String username;
    private String password;
    private String poolName = "App-Pool";
    private int maxPoolSize = 10;
    private int minIdle = 3;
    private long connectionTimeout = 2000;      // 2 seconds
    private long idleTimeout = 300000;          // 5 minutes
    private long maxLifetime = 1200000;         // 20 minutes (< PostgreSQL's 30min default)
    private long leakDetectionThreshold = 5000; // 5 seconds

    // getters + setters
    public String getUrl()                     { return url; }
    public String getUsername()                { return username; }
    public String getPassword()                { return password; }
    public String getPoolName()                { return poolName; }
    public int getMaxPoolSize()                { return maxPoolSize; }
    public int getMinIdle()                    { return minIdle; }
    public long getConnectionTimeout()         { return connectionTimeout; }
    public long getIdleTimeout()               { return idleTimeout; }
    public long getMaxLifetime()               { return maxLifetime; }
    public long getLeakDetectionThreshold()    { return leakDetectionThreshold; }

    public void setUrl(String u)                    { url = u; }
    public void setUsername(String u)               { username = u; }
    public void setPassword(String p)               { password = p; }
    public void setPoolName(String n)               { poolName = n; }
    public void setMaxPoolSize(int s)               { maxPoolSize = s; }
    public void setMinIdle(int m)                   { minIdle = m; }
    public void setConnectionTimeout(long t)        { connectionTimeout = t; }
    public void setIdleTimeout(long t)              { idleTimeout = t; }
    public void setMaxLifetime(long t)              { maxLifetime = t; }
    public void setLeakDetectionThreshold(long t)   { leakDetectionThreshold = t; }
}

@Configuration
@EnableConfigurationProperties(AppDataSourceProperties.class)
public class DataSourceConfig {

    @Bean
    public DataSource dataSource(AppDataSourceProperties props, MeterRegistry registry) {
        // Validate max-lifetime < DB timeout:
        if (props.getMaxLifetime() >= 1800000) {  // 30 min
            throw new IllegalStateException(
                "max-lifetime must be < PostgreSQL's wait_timeout (30min)");
        }

        HikariConfig cfg = new HikariConfig();
        cfg.setJdbcUrl(props.getUrl());
        cfg.setUsername(props.getUsername());
        cfg.setPassword(props.getPassword());
        cfg.setPoolName(props.getPoolName());
        cfg.setMaximumPoolSize(props.getMaxPoolSize());
        cfg.setMinimumIdle(props.getMinIdle());
        cfg.setConnectionTimeout(props.getConnectionTimeout());
        cfg.setIdleTimeout(props.getIdleTimeout());
        cfg.setMaxLifetime(props.getMaxLifetime());
        cfg.setLeakDetectionThreshold(props.getLeakDetectionThreshold());

        HikariDataSource ds = new HikariDataSource(cfg);

        // Register metrics with Micrometer:
        new HikariDataSourceMetrics(ds, java.util.List.of()).bindTo(registry);

        return ds;
    }
}

