CREATE INDEX CONCURRENTLY IF NOT EXISTS idx_products_category_price
    ON products(category, price)
    INCLUDE (id, name, active)
    WHERE active = true;  -- partial: only active products
-- category leftmost for equality filter
-- price second for BETWEEN range filter (range scan on index)
-- INCLUDE id, name, active: covering for SELECT + WHERE active check
-- WHERE active=true: partial - halves index size if 50% inactive

-- AFTER index:
-- Limit  (cost=0.25..1.23 rows=20)
--   -> Index Only Scan using idx_products_category_price on products
--        Index Cond: (category='Electronics') AND
--                    (price BETWEEN 500 AND 5000)
--        Filter: (active = true)  [from INCLUDE column]
--        Heap Fetches: 0
-- Execution Time: 0.6ms   ← 5000× faster!

import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.math.BigDecimal;
import java.util.List;

@DataJpaTest
class ProductSearchTest {
    @Autowired TestEntityManager testEm;
    @Autowired ProductRepository repo;

    @BeforeEach void seed() {
        testEm.persistAndFlush(new Product("TV",new BigDecimal("8000"),"Electronics",true));
        testEm.persistAndFlush(new Product("Mouse",new BigDecimal("799"),"Electronics",true));
        testEm.persistAndFlush(new Product("Keyboard",new BigDecimal("1999"),"Electronics",true));
        testEm.persistAndFlush(new Product("Chair",new BigDecimal("3000"),"Furniture",true));
        testEm.persistAndFlush(new Product("Monitor",new BigDecimal("15000"),"Electronics",true));
        testEm.persistAndFlush(new Product("USB Hub",new BigDecimal("499"),"Electronics",false));// inactive
        testEm.clear();
    }
    @Test void searchElectronics_500to5000_returnsCorrect() {
        List<Product> results = repo.findByCategoryAndPriceBetweenAndActiveTrueOrderByPriceAsc(
            "Electronics", new BigDecimal("500"), new BigDecimal("5000"));
        assertEquals(2, results.size()); // Mouse(799) + Keyboard(1999)
        assertEquals("Mouse", results.get(0).getName());
        assertEquals("Keyboard", results.get(1).getName());
    }
}

